from lxml import etree, objectify
from xml.sax.saxutils import escape
import sys

def process_soap_request(xml_data):
    try:
        # Parse the XML data with DTD validation
        parser = etree.XMLParser(dtd_validation=True)
        root = objectify.parse(xml_data, parser=parser)

        # Extract SOAP Envelope and SOAP Body elements
        envelope = root.getroottag()
        body = envelope[1]  # Assuming the first child of the Envelope is the Body

        # Extract the message body content (Assuming the first child of the Body is a tag containing the data)
        body_content = body[0].text

        return escape(body_content)
    except Exception as e:
        print(f"Error processing SOAP request: {e}", file=sys.stderr)
        return None